/* =====================================================
   CODING NAME RESOLVERS
   =====================================================
   Read codes against the masters to produce human-readable display strings.
   Used across every list view's expanded coding column set so the user sees
   "Mayfair Fine Dining" rather than "OUT-LON-01-REST-01", "Restaurant" rather
   than "CC-FDR", "6010 — Food cost of sales" rather than just "6010".

   All resolvers are defensive: missing codes/lookups return '—' (or the bare
   code) so an upstream data-shape issue won't crash a row render.
*/
const resolveOutletName = (outletCode) => {
  if (!outletCode) return null;
  for (const s of SITES) {
    const o = s.outlets?.find(x => x.outletId === outletCode);
    if (o) return o.name;
  }
  return null;
};
const resolveCostCentreName = (ccCode) => {
  if (!ccCode) return null;
  return COST_CENTRES.find(c => c.code === ccCode)?.name || null;
};
const resolveGlName = (glCode) => {
  if (!glCode) return null;
  return CHART_OF_ACCOUNTS.find(g => g.glCode === String(glCode))?.name || null;
};
const resolveDeptName = (deptCode) => {
  if (!deptCode) return null;
  return DEPARTMENTS.find(d => d.code === deptCode)?.name || null;
};
const resolveSiteName = (siteId) => {
  if (!siteId) return null;
  return SITES.find(s => s.siteId === siteId)?.name || null;
};
const resolveLegalEntityName = (leCode) => {
  if (!leCode) return null;
  // Accept either the code or an already-resolved name.
  const hit = LEGAL_ENTITIES.find(l => l.code === leCode || l.name === leCode);
  return hit?.name || null;
};
/* Resolve a coding object's dimensions to full names. Falls back to the raw
   code when a name can't be resolved, so nothing ever renders blank. Used
   everywhere coding is shown so people read "Restaurant" not "CC-FDR". */
const resolveCoding = (c, siteId) => {
  if (!c) return {};
  return {
    legalEntity: resolveLegalEntityName(c.legalEntity) || c.legalEntity || '—',
    site:        resolveSiteName(siteId || c.site) || siteId || c.site || '—',
    outlet:      resolveOutletName(c.outlet) || c.outlet || '—',
    dept:        resolveDeptName(c.dept) || c.dept || '—',
    costCentre:  resolveCostCentreName(c.costCentre) || c.costCentre || '—',
    glAccount:   (() => { const n = resolveGlName(c.glAccount); return n ? `${c.glAccount} · ${n}` : (c.glAccount || '—'); })(),
  };
};

/* Full-name version of the · -joined coding string, for detail/audit views. */
const codingNamesString = (coding, siteId) => {
  if (!coding) return '—';
  const n = resolveCoding(coding, siteId);
  return [n.legalEntity, n.site, n.outlet, n.dept, n.costCentre, n.glAccount].filter(x => x && x !== '—').join(' · ') || '—';
};

/* CodedCell — pair-render of a code with its master-resolved name. Reused
   in every list view's expanded coding columns so the visual treatment is
   identical (mono code on top, smaller secondary-grey name below). When
   the name is unresolved, falls back to just the code so missing
   references don't visually distract. */
function CodedCell({ code, name, codeStyle, nameStyle }) {
  const safeCode = code ?? '—';
  return (
    <div style={{ minWidth: 0 }}>
      <div className="pf-mono" style={{ fontSize: '11px', color: '#0D1424', fontWeight: 500, ...codeStyle }}>{safeCode}</div>
      {name && (
        <div style={{ fontSize: '9.5px', color: '#586278', marginTop: '1px', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', ...nameStyle }}>{name}</div>
      )}
    </div>
  );
}


