/* ── AI RIBBON ───────────────────────────────────── */
function TrkAIRibbon({ stage, proposals }){
  const [open,setOpen]=useState(false);
  const relevant=proposals.filter(p=>p.targetStage===stage);
  if(!relevant.length) return null;
  const overrides=relevant.filter(p=>p.status==='overridden').length;
  const accepted=relevant.filter(p=>p.status==='accepted').length;
  const pending=relevant.filter(p=>p.status==='pending').length;
  const noCtx=relevant.filter(p=>p.status==='no_proposal_lacked_context').length;
  return (
    <div style={{borderTop:'1px solid #E8ECF4',background:'rgba(109,74,196,0.03)'}}>
      <div onClick={()=>setOpen(o=>!o)} style={{display:'flex',alignItems:'center',gap:'10px',padding:'8px 18px',cursor:'pointer'}}>
        <span style={{fontFamily:"'JetBrains Mono',monospace",fontSize:'8.5px',letterSpacing:'0.1em',textTransform:'uppercase',color:'#6D4AC4',fontWeight:600}}>Sovereign AI</span>
        <span style={{fontSize:'10px',color:'#586278'}}>{accepted} accepted · {overrides} overridden{pending>0?` · ${pending} pending`:''}{noCtx>0?` · ${noCtx} no context`:''}</span>
        <span style={{marginLeft:'auto',fontSize:'10px',color:'#6D4AC4'}}>{open?'▲ hide':'▼ show'}</span>
      </div>
      {open && <div style={{borderTop:'1px solid rgba(109,74,196,0.12)',padding:'4px 18px 10px'}}>
        {relevant.map(p=>{
          const conf=Math.round((p.confidence||0)*100);
          const confColor=conf>=90?'#0E8C9E':conf>=70?'#B45309':'#B33A1F';
          const statusColor={accepted:'#0E8C9E',overridden:'#B33A1F',pending:'#B45309',no_proposal_lacked_context:'#8892A6'}[p.status];
          return (
            <div key={p.id} style={{padding:'8px 0',borderBottom:'1px dashed rgba(109,74,196,0.12)'}}>
              <div style={{display:'flex',alignItems:'center',gap:'8px',flexWrap:'wrap'}}>
                <span style={{fontFamily:"'JetBrains Mono',monospace",fontSize:'9px',color:'#8892A6'}}>{p.targetField}</span>
                <span style={{fontSize:'10.5px',fontWeight:500,color:'#0D1424'}}>{p.status==='no_proposal_lacked_context'?<i style={{color:'#8892A6'}}>insufficient context</i>:p.proposedValue}</span>
                <span style={{fontFamily:"'JetBrains Mono',monospace",fontSize:'9px',color:confColor}}>{conf}%</span>
                <span style={{fontFamily:"'JetBrains Mono',monospace",fontSize:'8px',fontWeight:600,padding:'1px 6px',borderRadius:'3px',color:statusColor,background:`${statusColor}15`,border:`1px solid ${statusColor}40`}}>{p.status.replace(/_/g,' ').toUpperCase()}</span>
              </div>
              <div style={{fontSize:'10px',color:'#8892A6',marginTop:'3px',fontStyle:'italic'}}>{p.reasoning}</div>
              {p.status==='overridden'&&p.decision&&(
                <div style={{marginTop:'4px',fontSize:'10px',color:'#B33A1F',background:'rgba(179,58,31,0.04)',padding:'4px 8px',borderRadius:'4px',borderLeft:'2px solid #B33A1F'}}>
                  Override → <b>{p.decision.decidedValue}</b> by {p.decision.decidedBy}{p.decision.note&&` — "${p.decision.note}"`}
                </div>
              )}
              {p.status==='pending'&&(
                <div style={{marginTop:'4px',fontSize:'10px',color:'#B45309',background:'rgba(180,83,9,0.04)',padding:'4px 8px',borderRadius:'4px',borderLeft:'2px solid #B45309'}}>
                  Awaiting human decision
                </div>
              )}
            </div>
          );
        })}
      </div>}
    </div>
  );
}

